import { GameState, GameEvent } from '../types';
import { generateYearlyEvent } from './geminiService';
import { STATIC_EVENTS } from '../data/events/staticEvents';

export class EventController {
    /**
     * 生成下一季度的事件
     * 优先尝试 Gemini 生成，失败则从静态库抽取
     */
    static async generateNextEvent(state: GameState): Promise<GameEvent> {
        try {
            // 80% 概率尝试 AI 生成，20% 概率使用静态库增加稳定性
            if (Math.random() < 0.8) {
                const aiEvent = await generateYearlyEvent(state);
                if (aiEvent) return aiEvent;
            }
        } catch (e) {
            console.error("Gemini Event Generation Failed:", e);
        }

        // 保底逻辑
        const randomIndex = Math.floor(Math.random() * STATIC_EVENTS.length);
        return { ...STATIC_EVENTS[randomIndex] };
    }

    /**
     * 处理事件选择后的状态更新
     */
    static processEventChoice(state: GameState, event: GameEvent, choiceKey: 'choiceA' | 'choiceB'): Partial<GameState> {
        const impact = event.impact;
        const currentYear = state.year;

        // 这里的逻辑可以根据具体 choiceKey 做差异化，目前由于 Gemini 返回的是统一 impact，我们做基础叠加
        // 未来可以在 impact 中定义 impactA 和 impactB

        return {
            spiritStones: state.spiritStones + (impact.spiritStones || 0),
            merit: state.merit + (impact.merit || 0),
            luck: state.luck + (impact.luck || 0),
            logs: [
                impact.log || `【${currentYear}载·因果】处理了：${event.title}`,
                ...state.logs
            ].slice(0, 30)
        };
    }
}

